/**
 * InkNeighbour Service Worker
 * Handles: Browser Push Notifications + Basic Offline Caching
 *
 * This file lives at /public/sw.js and is served as /sw.js
 * It supplements the Workbox service worker generated by vite-plugin-pwa.
 */

const CACHE_NAME = 'inkneighbour-v1'
const OFFLINE_URLS = [
  '/',
  '/index.html'
]

// ============================================================
// Install: pre-cache critical shell
// ============================================================
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then(cache => cache.addAll(OFFLINE_URLS))
  )
  self.skipWaiting()
})

// ============================================================
// Activate: clean old caches
// ============================================================
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then(keys =>
      Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
    )
  )
  self.clients.claim()
})

// ============================================================
// Fetch: network-first for API, cache-first for assets
// ============================================================
self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url)

  // Don't cache Supabase API requests
  if (url.hostname.includes('supabase.co')) return

  // Cache-first for static assets
  if (event.request.destination === 'image' || url.pathname.match(/\.(js|css|woff2?)$/)) {
    event.respondWith(
      caches.match(event.request).then(cached => {
        if (cached) return cached
        return fetch(event.request).then(response => {
          const clone = response.clone()
          caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone))
          return response
        })
      })
    )
    return
  }

  // Network-first for HTML navigation
  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request).catch(() =>
        caches.match('/index.html')
      )
    )
  }
})

// ============================================================
// Push: receive and display push notifications for owners
// ============================================================
self.addEventListener('push', (event) => {
  if (!event.data) return

  let data
  try {
    data = event.data.json()
  } catch {
    data = { title: 'InkNeighbour', body: event.data.text() }
  }

  const options = {
    body: data.body || 'You have a new print job.',
    icon: data.icon || '/icon-192.png',
    badge: data.badge || '/badge-72.png',
    vibrate: [200, 100, 200],
    data: data.data || {},
    actions: [
      { action: 'view', title: 'View job' },
      { action: 'dismiss', title: 'Dismiss' }
    ]
  }

  event.waitUntil(
    self.registration.showNotification(data.title || 'New Print Job', options)
  )
})

// ============================================================
// Notification click: open dashboard
// ============================================================
self.addEventListener('notificationclick', (event) => {
  event.notification.close()

  if (event.action === 'dismiss') return

  const url = event.notification.data?.url || '/dashboard'

  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true }).then(clientList => {
      // Focus existing window if open
      for (const client of clientList) {
        if (client.url.includes(self.location.origin) && 'focus' in client) {
          client.navigate(url)
          return client.focus()
        }
      }
      // Open new window
      if (clients.openWindow) {
        return clients.openWindow(url)
      }
    })
  )
})
